vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uvo = vUv;

vec2 rotate_uv = 0.5-uv_rotate(0 + (vUv-0.5)*uAspect.xy, 0, q3, q4, 2);
vec2 bipolar_uv = uv_bipolar(rotate_uv,vec2(0,0.5),vec2(1,0.5), 2, 0.3, vec2(q11,q12));
vUv = 0.5 + (0.5 - abs( fract( bipolar_uv * 0.5 ) * 2.0 - 1.0 ));

vec2 uv1 = vUv-.5;

vec3 ret1 = texture(sampler_main, vUv) +texture(sampler_main, 1-vUv)*0;


vec2 hor = vec2 (uTexSize.z,0);
vec2 ver = vec2 (0,uTexSize.w);
float dx = GetPixel (vUv-hor) - GetPixel (vUv+hor);
float dy = GetPixel (vUv-ver) - GetPixel (vUv+ver);
vec2 dz = vec2 (dx,dy);

uv1 = uv1*0+.2*cos(uv1*2+1.8) - dz;;
vec3 dots = clamp01(.03/length(uv1))*vec3(1,1,1);


ret1 = q1*(-ret1/2) + dots*0 + .0 + 7*dots*(-0.1+ret1);

ret = .8*ret1;

  fragColor = ret;
}
